"use client";
import { useState } from "react";
import { ethers } from "ethers";

export default function Home() {
  const [walletAddress, setWalletAddress] = useState("");
  const [activeDrift, setActiveDrift] = useState("streaming");
  
  // Advanced Loading States
  const [isDeploying, setIsDeploying] = useState(false);
  const [loadingText, setLoadingText] = useState("Initialize Drift");
  
  const [activeStreams, setActiveStreams] = useState<any[]>([]);
  const [recipient, setRecipient] = useState("");
  const [amount, setAmount] = useState("");
  const [duration, setDuration] = useState("");

  // ⚠️ THE BLOCKCHAIN REQUIRES REAL ADDRESSES HERE ⚠️
  // If you leave the dummy USDC address, the on-chain approval WILL fail.
  const CONTRACT_ADDRESS = "0x24747a21Fe0899dC4a5323E26778B66B3BF0C2dA"; 
  const USDC_ADDRESS = "0x3600000000000000000000000000000000000000"; 

  const MINIMAL_ABI = [
    "function createDrift(address _recipient, uint256 _amount, uint256 _startTime, uint256 _endTime, uint8 _ruleType) external returns (uint256)"
  ];
  
  const ERC20_ABI = [
    "function approve(address spender, uint256 amount) public returns (bool)"
  ];

  const connectWallet = async () => {
    if (typeof window !== "undefined" && window.ethereum) {
      try {
        const accounts = await window.ethereum.request({ method: "eth_requestAccounts" });
        setWalletAddress(accounts[0].slice(0, 6) + "..." + accounts[0].slice(-4));
      } catch (err) {
        console.error("Connection failed", err);
      }
    } else {
      alert("MetaMask not found!");
    }
  };

  const handleDeploy = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!walletAddress) return alert("Connect your wallet first!");

    setIsDeploying(true);

    try {
      const provider = new ethers.BrowserProvider(window.ethereum as any);
      const signer = await provider.getSigner();
      const parsedAmount = ethers.parseUnits(amount, 18);

      // --- STRICT ON-CHAIN STEP 1: APPROVE TOKENS ---
      setLoadingText("Approving USDC...");
      const usdcContract = new ethers.Contract(USDC_ADDRESS, ERC20_ABI, signer);
      
      console.log("Waiting for on-chain Approval...");
      const approveTx = await usdcContract.approve(CONTRACT_ADDRESS, parsedAmount);
      await approveTx.wait(); // This will explicitly throw an error if the user rejects or has no gas
      console.log("Approval Confirmed!");

      // --- STRICT ON-CHAIN STEP 2: CREATE DRIFT ---
      setLoadingText("Broadcasting Protocol...");
      const driftContract = new ethers.Contract(CONTRACT_ADDRESS, MINIMAL_ABI, signer);

      const startTime = Math.floor(Date.now() / 1000); 
      const durationInSeconds = Number(duration) * 3600; 
      const endTime = startTime + durationInSeconds;
      
      let ruleTypeEnum = activeDrift === "delayed" ? 1 : activeDrift === "cancelable" ? 2 : 0;

      console.log("Waiting for on-chain Drift Creation...");
      const tx = await driftContract.createDrift(recipient, parsedAmount, startTime, endTime, ruleTypeEnum);
      await tx.wait(); // Wait for actual block confirmation
      console.log("Drift Creation Confirmed! Hash:", tx.hash);

      // --- STEP 3: UPDATE DASHBOARD ---
      // Only runs if the blockchain strictly confirmed both transactions above
      const newStream = {
        id: tx.hash.substring(0, 8), // Using real Tx hash for the ID
        type: activeDrift,
        recipient: recipient.slice(0, 6) + "..." + recipient.slice(-4),
        amount: amount,
        timeRemaining: duration + " hrs",
        status: "Active 🟢"
      };
      
      setActiveStreams([newStream, ...activeStreams]);
      setRecipient(""); setAmount(""); setDuration("");
      alert("Protocol Live: Real On-Chain Transaction Confirmed!");

    } catch (err: any) {
      console.error(err);
      alert(`Blockchain Error: Transaction Reverted. Do you have Testnet USDC and Gas? \n\nDetails: ${err.reason || err.message}`);
    } finally {
      setIsDeploying(false);
      setLoadingText("Initialize Drift");
    }
  };

  return (
    <main className="min-h-screen bg-[#07090E] text-white font-sans selection:bg-blue-500/30 pb-20">
      
      {/* PERFECTED CSS-ONLY NAVBAR */}
      <nav className="flex justify-between items-center p-6 mb-8">
        <div className="flex items-center gap-3">
          {/* Pure CSS Web3 Logo - No Image Files Required */}
          <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-[#7B5EFA] to-[#3B82F6] flex items-center justify-center shadow-[0_0_15px_rgba(123,94,250,0.4)]">
            <div className="w-4 h-5 border-2 border-white rounded-t-full border-b-0 mt-1"></div>
          </div>
          <div className="text-2xl font-bold tracking-tight">
            ARC <span className="text-gray-500 font-medium">Drift</span>
          </div>
        </div>
        <button onClick={connectWallet} className="bg-[#7B5EFA] hover:bg-[#684be3] px-6 py-2.5 rounded-xl font-semibold shadow-[0_0_20px_rgba(123,94,250,0.3)] text-sm">
          {walletAddress ? walletAddress : "Connect Wallet"}
        </button>
      </nav>
      
      <div className="flex flex-col items-center px-4">
        <div className="w-full max-w-[500px] bg-[#0E121A] border border-[#1C2333] rounded-[2rem] p-8 shadow-2xl mb-12">
          <div className="flex items-center gap-4 mb-8">
            <div className="w-12 h-12 rounded-2xl bg-[#1C2333] flex items-center justify-center text-blue-400 font-light text-3xl">+</div>
            <h2 className="text-2xl font-bold tracking-wide">Deploy Drift</h2>
            <span className="ml-auto px-3 py-1.5 rounded-full border border-gray-700 bg-gray-800/40 text-[10px] font-bold text-gray-400 uppercase">Simulation V2.4</span>
          </div>

          <div className="grid grid-cols-2 gap-4 mb-8">
            <DriftCard id="delayed" title="Delayed Transfer" icon="🕒" isActive={activeDrift === "delayed"} onClick={() => setActiveDrift("delayed")} />
            <DriftCard id="streaming" title="Streaming Payment" icon="🌊" isActive={activeDrift === "streaming"} onClick={() => setActiveDrift("streaming")} />
            <DriftCard id="cancelable" title="Cancelable Transfer" icon="🚫" isActive={activeDrift === "cancelable"} onClick={() => setActiveDrift("cancelable")} />
            <DriftCard id="recurring" title="Recurring Payment" icon="🔁" isActive={activeDrift === "recurring"} onClick={() => setActiveDrift("recurring")} />
          </div>

          <form onSubmit={handleDeploy} className="flex flex-col gap-6">
            <div>
              <label className="block text-[#64748B] text-xs font-bold mb-2 uppercase">Recipient Address</label>
              <input type="text" placeholder="0x..." value={recipient} onChange={(e) => setRecipient(e.target.value)} className="w-full bg-[#151B28] border border-[#232D42] text-gray-300 p-4 rounded-xl focus:outline-none focus:border-[#7B5EFA] font-mono text-sm" required />
            </div>
            <div className="flex gap-4">
              <div className="w-1/2">
                <label className="block text-[#64748B] text-xs font-bold mb-2 uppercase">Amount (ARC)</label>
                <input type="number" placeholder="1" value={amount} onChange={(e) => setAmount(e.target.value)} className="w-full bg-[#151B28] border border-[#232D42] text-gray-300 p-4 rounded-xl focus:outline-none focus:border-[#7B5EFA] font-mono text-sm" required />
              </div>
              <div className="w-1/2">
                <label className="block text-[#64748B] text-xs font-bold mb-2 uppercase">Duration (HRS)</label>
                <input type="number" placeholder="24" value={duration} onChange={(e) => setDuration(e.target.value)} className="w-full bg-[#151B28] border border-[#232D42] text-gray-300 p-4 rounded-xl focus:outline-none focus:border-[#7B5EFA] font-mono text-sm" required />
              </div>
            </div>

            <button type="submit" disabled={isDeploying} className={`w-full text-white font-bold py-4 rounded-xl mt-4 text-lg shadow-[0_0_20px_rgba(123,94,250,0.2)] ${isDeploying ? 'bg-gray-600 cursor-not-allowed' : 'bg-[#7B5EFA] hover:bg-[#684be3]'}`}>
              {loadingText}
            </button>
          </form>
        </div>

        <div className="w-full max-w-[800px] mt-8">
          <h3 className="text-xl font-bold mb-4 border-b border-[#1C2333] pb-4">Protocol Registry (Active Drifts)</h3>
          {activeStreams.length === 0 ? (
            <div className="text-center py-10 text-[#64748B] border border-dashed border-[#1C2333] rounded-xl bg-[#0E121A]/50">No active streams detected.</div>
          ) : (
            <div className="flex flex-col gap-3">
              {activeStreams.map((stream) => (
                <div key={stream.id} className="flex items-center justify-between bg-[#151B28] p-4 rounded-xl border border-[#232D42]">
                  <div className="flex items-center gap-4">
                    <div className="bg-[#1C2333] p-2 rounded-lg text-xl">{stream.type === 'streaming' ? '🌊' : stream.type === 'delayed' ? '🕒' : stream.type === 'cancelable' ? '🚫' : '🔁'}</div>
                    <div><div className="text-sm text-gray-400">Recipient</div><div className="font-mono text-blue-400">{stream.recipient}</div></div>
                  </div>
                  <div className="text-center"><div className="text-sm text-gray-400">Amount</div><div className="font-bold text-white">{stream.amount} ARC</div></div>
                  <div className="text-center"><div className="text-sm text-gray-400">Duration</div><div className="font-mono text-gray-300">{stream.timeRemaining}</div></div>
                  <div className="text-right"><div className="text-sm text-gray-400">Status</div><div className="text-green-400 text-sm font-bold uppercase">{stream.status}</div></div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </main>
  );
}

function DriftCard({ id, title, icon, isActive, onClick }: any) {
  return (
    <div onClick={onClick} className={`cursor-pointer p-4 rounded-2xl border transition-all flex flex-col h-32 justify-end relative overflow-hidden ${isActive ? 'bg-[#18243E]/50 border-[#3B82F6] shadow-[0_0_15px_rgba(59,130,246,0.15)]' : 'bg-[#151B28] border-[#232D42] hover:border-gray-600'}`}>
      <div className={`absolute top-4 left-4 w-10 h-10 rounded-full flex items-center justify-center text-lg ${isActive ? 'bg-[#3B82F6]/20 text-[#3B82F6]' : 'bg-[#1C2333] text-gray-400'}`}>{icon}</div>
      <h3 className={`font-semibold text-sm ${isActive ? 'text-white' : 'text-gray-400'}`}>{title.split(' ').map((word: string, i: number) => <div key={i}>{word}</div>)}</h3>
    </div>
  );
}